import{_ as a,o as e,c as l,a4 as s}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"工业流程套路","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Review-Routine-004-工业流程套路-V1.0-20260405.md","filePath":"chemistry/Chem-Review-Routine-004-工业流程套路-V1.0-20260405.md"}'),n={name:"chemistry/Chem-Review-Routine-004-工业流程套路-V1.0-20260405.md"};function i(r,t,d,p,o,h){return e(),l("div",null,[...t[0]||(t[0]=[s(`<h1 id="工业流程套路" tabindex="-1">工业流程套路 <a class="header-anchor" href="#工业流程套路" aria-label="Permalink to &quot;工业流程套路&quot;">​</a></h1><p><strong>高考化学压轴题之一——工业流程题解题模板</strong></p><hr><h2 id="题型认知" tabindex="-1">题型认知 <a class="header-anchor" href="#题型认知" aria-label="Permalink to &quot;题型认知&quot;">​</a></h2><h3 id="题目特征" tabindex="-1">题目特征 <a class="header-anchor" href="#题目特征" aria-label="Permalink to &quot;题目特征&quot;">​</a></h3><ul><li>以工业生产为背景（如制备某种产品）</li><li>流程图形式呈现</li><li>涉及元素化合物知识的综合应用</li><li>常考陌生方程式书写、操作目的、条件选择</li></ul><h3 id="分值分布" tabindex="-1">分值分布 <a class="header-anchor" href="#分值分布" aria-label="Permalink to &quot;分值分布&quot;">​</a></h3><ul><li>通常14-16分</li><li>6-8个小问</li><li>难度梯度明显（前3问基础，后几问拔高）</li></ul><hr><h2 id="解题四步法" tabindex="-1">解题四步法 <a class="header-anchor" href="#解题四步法" aria-label="Permalink to &quot;解题四步法&quot;">​</a></h2><h3 id="第一步-看头看尾-30秒" tabindex="-1">第一步：看头看尾（30秒） <a class="header-anchor" href="#第一步-看头看尾-30秒" aria-label="Permalink to &quot;第一步：看头看尾（30秒）&quot;">​</a></h3><p><strong>看什么</strong>：</p><ul><li><strong>原料</strong>：是什么？（矿石、废料、气体等）</li><li><strong>产品</strong>：目标产物是什么？</li><li><strong>杂质</strong>：原料中有哪些杂质需要除去？</li></ul><p><strong>目的</strong>：明确整个流程的转化目标</p><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原料：铝土矿（含Al₂O₃、Fe₂O₃、SiO₂）</span></span>
<span class="line"><span>产品：提纯Al₂O₃</span></span>
<span class="line"><span>任务：除去Fe₂O₃、SiO₂</span></span></code></pre></div><hr><h3 id="第二步-分析流程-2分钟" tabindex="-1">第二步：分析流程（2分钟） <a class="header-anchor" href="#第二步-分析流程-2分钟" aria-label="Permalink to &quot;第二步：分析流程（2分钟）&quot;">​</a></h3><p><strong>分析方法</strong>：</p><ul><li>顺着箭头走，分析每一步发生了什么</li><li>写出关键反应的化学方程式</li><li>标注每步除去了什么杂质/得到了什么产物</li></ul><p><strong>常见操作符号</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">符号</th><th style="text-align:center;">含义</th><th style="text-align:left;">考点</th></tr></thead><tbody><tr><td style="text-align:center;">粉碎</td><td style="text-align:center;">增大接触面积</td><td style="text-align:left;">加快反应速率</td></tr><tr><td style="text-align:center;">焙烧/煅烧</td><td style="text-align:center;">高温加热</td><td style="text-align:left;">改变物质结构，便于后续处理</td></tr><tr><td style="text-align:center;">酸浸/碱浸</td><td style="text-align:center;">用酸/碱溶解</td><td style="text-align:left;">选择性溶解，分离杂质</td></tr><tr><td style="text-align:center;">过滤</td><td style="text-align:center;">固液分离</td><td style="text-align:left;">操作要点、洗涤检验</td></tr><tr><td style="text-align:center;">蒸发浓缩</td><td style="text-align:center;">减少溶剂</td><td style="text-align:left;">结晶前准备</td></tr><tr><td style="text-align:center;">冷却结晶</td><td style="text-align:center;">降低温度</td><td style="text-align:left;">溶解度随温度变化大的物质</td></tr><tr><td style="text-align:center;">趁热过滤</td><td style="text-align:center;">高温下过滤</td><td style="text-align:left;">防止目标物质析出</td></tr><tr><td style="text-align:center;">调节pH</td><td style="text-align:center;">加酸或碱</td><td style="text-align:left;">使某些离子沉淀</td></tr></tbody></table><hr><h3 id="第三步-关注循环-30秒" tabindex="-1">第三步：关注循环（30秒） <a class="header-anchor" href="#第三步-关注循环-30秒" aria-label="Permalink to &quot;第三步：关注循环（30秒）&quot;">​</a></h3><p><strong>什么是循环</strong>：</p><ul><li>流程中有些物质从后面回到前面</li><li>通常是副产物或溶剂</li></ul><p><strong>为什么重要</strong>：</p><ul><li>常考&quot;可循环利用的物质&quot;</li><li>体现绿色化学思想</li><li>降低生产成本</li></ul><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>制备硫酸的流程中，SO₂催化氧化生成SO₃，</span></span>
<span class="line"><span>未反应的SO₂可以循环使用。</span></span></code></pre></div><hr><h3 id="第四步-答题-按问作答" tabindex="-1">第四步：答题（按问作答） <a class="header-anchor" href="#第四步-答题-按问作答" aria-label="Permalink to &quot;第四步：答题（按问作答）&quot;">​</a></h3><p><strong>常见题型与答题模板</strong>：</p><h4 id="_1-书写化学方程式" tabindex="-1">1. 书写化学方程式 <a class="header-anchor" href="#_1-书写化学方程式" aria-label="Permalink to &quot;1. 书写化学方程式&quot;">​</a></h4><p><strong>陌生方程式书写步骤</strong>：</p><ol><li>找出反应物和生成物（根据流程和元素守恒）</li><li>判断反应类型（氧化还原？复分解？）</li><li>配平</li><li>注明条件</li></ol><p><strong>示例</strong>（用软锰矿制备MnO₂）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MnO₂ + 4HCl(浓) =△= MnCl₂ + Cl₂↑ + 2H₂O</span></span></code></pre></div><hr><h4 id="_2-解释操作目的" tabindex="-1">2. 解释操作目的 <a class="header-anchor" href="#_2-解释操作目的" aria-label="Permalink to &quot;2. 解释操作目的&quot;">​</a></h4><p><strong>答题模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目的：...（除去什么/获得什么/改变什么）</span></span>
<span class="line"><span>原理：...（化学方程式或原理说明）</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li><p>问：为什么要粉碎矿石？</p></li><li><p>答：增大接触面积，加快反应速率，提高浸取效率。</p></li><li><p>问：为什么要趁热过滤？</p></li><li><p>答：防止目标产物因温度降低而析出，造成损失。</p></li></ul><hr><h4 id="_3-选择反应条件" tabindex="-1">3. 选择反应条件 <a class="header-anchor" href="#_3-选择反应条件" aria-label="Permalink to &quot;3. 选择反应条件&quot;">​</a></h4><p><strong>常见条件</strong>：温度、酸碱度、浓度、催化剂</p><p><strong>答题角度</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">条件</th><th style="text-align:left;">考虑因素</th></tr></thead><tbody><tr><td style="text-align:left;">温度</td><td style="text-align:left;">反应速率、平衡移动、物质稳定性、能耗</td></tr><tr><td style="text-align:left;">pH</td><td style="text-align:left;">离子沉淀完全、防止副反应、产品纯度</td></tr><tr><td style="text-align:left;">浓度</td><td style="text-align:left;">反应速率、产物产率、成本</td></tr><tr><td style="text-align:left;">催化剂</td><td style="text-align:left;">反应速率、选择性</td></tr></tbody></table><p><strong>示例</strong>：</p><ul><li>问：为什么选择80℃而不是100℃？</li><li>答：80℃时反应速率较快，且避免了100℃时水的过度蒸发/某些物质的分解/能耗过高。</li></ul><hr><h4 id="_4-检验洗涤干净" tabindex="-1">4. 检验洗涤干净 <a class="header-anchor" href="#_4-检验洗涤干净" aria-label="Permalink to &quot;4. 检验洗涤干净&quot;">​</a></h4><p><strong>答题模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>取最后一次洗涤液少许于试管中，</span></span>
<span class="line"><span>加入...试剂，</span></span>
<span class="line"><span>若...现象，则已洗净；</span></span>
<span class="line"><span>若...现象，则未洗净。</span></span></code></pre></div><p><strong>示例</strong>（检验BaSO₄沉淀是否洗净）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>取最后一次洗涤液少许于试管中，</span></span>
<span class="line"><span>加入AgNO₃溶液和稀HNO₃，</span></span>
<span class="line"><span>若无白色沉淀产生，则已洗净；</span></span>
<span class="line"><span>若有白色沉淀产生，则未洗净（说明还有Cl⁻）。</span></span></code></pre></div><hr><h4 id="_5-计算产率-纯度" tabindex="-1">5. 计算产率/纯度 <a class="header-anchor" href="#_5-计算产率-纯度" aria-label="Permalink to &quot;5. 计算产率/纯度&quot;">​</a></h4><p><strong>产率公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>产率 = (实际产量 / 理论产量) × 100%</span></span></code></pre></div><p><strong>纯度公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>纯度 = (纯品质量 / 样品总质量) × 100%</span></span></code></pre></div><hr><h2 id="高频考点速查" tabindex="-1">高频考点速查 <a class="header-anchor" href="#高频考点速查" aria-label="Permalink to &quot;高频考点速查&quot;">​</a></h2><h3 id="原料预处理" tabindex="-1">原料预处理 <a class="header-anchor" href="#原料预处理" aria-label="Permalink to &quot;原料预处理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">目的</th></tr></thead><tbody><tr><td style="text-align:left;">粉碎</td><td style="text-align:left;">增大接触面积，加快反应速率</td></tr><tr><td style="text-align:left;">焙烧</td><td style="text-align:left;">改变物质结构，使其更易被酸/碱溶解</td></tr><tr><td style="text-align:left;">酸浸</td><td style="text-align:left;">溶解金属氧化物，与不溶杂质分离</td></tr><tr><td style="text-align:left;">碱浸</td><td style="text-align:left;">溶解酸性氧化物（如SiO₂、Al₂O₃）</td></tr></tbody></table><h3 id="除杂方法" tabindex="-1">除杂方法 <a class="header-anchor" href="#除杂方法" aria-label="Permalink to &quot;除杂方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">原理</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;">调节pH</td><td style="text-align:left;">使某些离子形成氢氧化物沉淀</td><td style="text-align:left;">调pH除去Fe³⁺、Al³⁺</td></tr><tr><td style="text-align:left;">氧化还原</td><td style="text-align:left;">将杂质离子转化为易除去的形态</td><td style="text-align:left;">将Fe²⁺氧化为Fe³⁺再调pH除去</td></tr><tr><td style="text-align:left;">萃取</td><td style="text-align:left;">利用溶解度差异分离</td><td style="text-align:left;">萃取分离金属离子</td></tr><tr><td style="text-align:left;">电解</td><td style="text-align:left;">利用电化学性质分离</td><td style="text-align:left;">电解精炼铜</td></tr></tbody></table><h3 id="结晶方法选择" tabindex="-1">结晶方法选择 <a class="header-anchor" href="#结晶方法选择" aria-label="Permalink to &quot;结晶方法选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">适用情况</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;">蒸发结晶</td><td style="text-align:left;">溶解度随温度变化小的物质</td><td style="text-align:left;">NaCl</td></tr><tr><td style="text-align:left;">冷却结晶</td><td style="text-align:left;">溶解度随温度变化大的物质</td><td style="text-align:left;">KNO₃、CuSO₄·5H₂O</td></tr><tr><td style="text-align:left;">趁热过滤</td><td style="text-align:left;">防止目标物质在低温下析出</td><td style="text-align:left;">除去杂质，保留热溶液中的产品</td></tr></tbody></table><hr><h2 id="经典流程模板" tabindex="-1">经典流程模板 <a class="header-anchor" href="#经典流程模板" aria-label="Permalink to &quot;经典流程模板&quot;">​</a></h2><h3 id="模板1-铝土矿制备氧化铝" tabindex="-1">模板1：铝土矿制备氧化铝 <a class="header-anchor" href="#模板1-铝土矿制备氧化铝" aria-label="Permalink to &quot;模板1：铝土矿制备氧化铝&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>铝土矿(Al₂O₃、Fe₂O₃、SiO₂)</span></span>
<span class="line"><span>    ↓ 加NaOH溶液</span></span>
<span class="line"><span>NaAlO₂溶液（Fe₂O₃不溶，过滤除去）</span></span>
<span class="line"><span>    ↓ 通入CO₂</span></span>
<span class="line"><span>Al(OH)₃沉淀</span></span>
<span class="line"><span>    ↓ 灼烧</span></span>
<span class="line"><span>Al₂O₃</span></span></code></pre></div><h3 id="模板2-软锰矿制备二氧化锰" tabindex="-1">模板2：软锰矿制备二氧化锰 <a class="header-anchor" href="#模板2-软锰矿制备二氧化锰" aria-label="Permalink to &quot;模板2：软锰矿制备二氧化锰&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>软锰矿(MnO₂)</span></span>
<span class="line"><span>    ↓ 加浓HCl、加热</span></span>
<span class="line"><span>MnCl₂溶液</span></span>
<span class="line"><span>    ↓ 加NaClO₃氧化</span></span>
<span class="line"><span>MnO₂沉淀</span></span>
<span class="line"><span>    ↓ 洗涤、干燥</span></span>
<span class="line"><span>产品MnO₂</span></span></code></pre></div><h3 id="模板3-工业废渣回收金属" tabindex="-1">模板3：工业废渣回收金属 <a class="header-anchor" href="#模板3-工业废渣回收金属" aria-label="Permalink to &quot;模板3：工业废渣回收金属&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>废渣（含Cu、Fe、Zn等）</span></span>
<span class="line"><span>    ↓ 加酸溶解</span></span>
<span class="line"><span>Cu²⁺、Fe²⁺、Zn²⁺溶液</span></span>
<span class="line"><span>    ↓ 调节pH分步沉淀</span></span>
<span class="line"><span>分步回收各种金属</span></span></code></pre></div><hr><h2 id="faq-常见问题" tabindex="-1">FAQ（常见问题） <a class="header-anchor" href="#faq-常见问题" aria-label="Permalink to &quot;FAQ（常见问题）&quot;">​</a></h2><h3 id="q1-流程图太复杂看不懂怎么办" tabindex="-1">Q1：流程图太复杂看不懂怎么办？ <a class="header-anchor" href="#q1-流程图太复杂看不懂怎么办" aria-label="Permalink to &quot;Q1：流程图太复杂看不懂怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>不要试图一次性看懂整个流程</li><li>先看原料和产品，明确目标</li><li>然后顺着箭头一步步看</li><li>不懂的地方先跳过，做完其他题再回来看</li></ol><h3 id="q2-陌生方程式怎么写" tabindex="-1">Q2：陌生方程式怎么写？ <a class="header-anchor" href="#q2-陌生方程式怎么写" aria-label="Permalink to &quot;Q2：陌生方程式怎么写？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>找出反应物和生成物（题目信息+流程+元素守恒）</li><li>判断反应类型（氧化还原用化合价升降法配平）</li><li>配平后检查原子守恒和电荷守恒</li><li>必要时查标准电极电势判断产物</li></ol><h3 id="q3-条件选择题怎么答" tabindex="-1">Q3：条件选择题怎么答？ <a class="header-anchor" href="#q3-条件选择题怎么答" aria-label="Permalink to &quot;Q3：条件选择题怎么答？&quot;">​</a></h3><p><strong>A</strong>：从这几个角度分析：</p><ul><li>速率：温度高、浓度大→速率快</li><li>平衡：温度、压强对平衡的影响</li><li>副反应：温度过高可能有副反应</li><li>成本：条件越苛刻成本越高</li><li>安全：某些条件下可能不安全</li></ul><h3 id="q4-循环利用的物质怎么找" tabindex="-1">Q4：循环利用的物质怎么找？ <a class="header-anchor" href="#q4-循环利用的物质怎么找" aria-label="Permalink to &quot;Q4：循环利用的物质怎么找？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>看流程中有没有从后面回到前面的箭头</li><li>看哪些物质既是反应物又是生成物</li><li>常见可循环：溶剂（水、有机溶剂）、酸、碱、未反应的原料气</li></ol><hr><h2 id="实战演练-checklist" tabindex="-1">实战演练 checklist <a class="header-anchor" href="#实战演练-checklist" aria-label="Permalink to &quot;实战演练 checklist&quot;">​</a></h2><p>拿到一道工业流程题：</p><ul><li>[ ] 看原料和产品（30秒）</li><li>[ ] 分析主要流程步骤（2分钟）</li><li>[ ] 找出循环利用的物质（30秒）</li><li>[ ] 按问作答，不会的跳过</li><li>[ ] 检查方程式配平和条件</li></ul><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Review-Routine-004<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>适用题型</strong>: 工业流程题（14-16分）<br><strong>配套文档</strong>: Chem-Learn-Detail-002 元素化合物详解</p><hr><p><em>工业流程题本质是元素化合物知识的综合应用，把握流程逻辑，规范答题，拿满分不是梦。</em></p>`,102)])])}const u=a(n,[["render",i]]);export{g as __pageData,u as default};
